patch:
--- a/adder.v
+++ b/adder.v
@@ -1,5 +1,5 @@
 module adder_8bit(
-  input [7:0] a, b,
-  output [8:0] sum
+  input [7:0] a, b,
+  output [7:0] sum
 );
   assign sum = a + b;

before_code:
module adder_8bit(
  input [7:0] a, b,
  output [8:0] sum
);
  assign sum = a + b;
endmodule

module top(
  input [7:0] x, y,
  output [7:0] result
);
  wire [7:0] temp;
  adder_8bit u1(.a(x), .b(y), .sum(temp));
  assign result = temp;
endmodule

after_code:
module adder_8bit(
  input [7:0] a, b,
  output [7:0] sum
);
  assign sum = a + b;
endmodule

module top(
  input [7:0] x, y,
  output [7:0] result
);
